const n={name:"Fänkål",icon:"fankal",family:"Flockblommiga",familyLatin:"Apiaceae",difficulty:"Medel",difficultyWhy:"Knölfänkålen är lite av en diva - hon skjuter i blom vid minsta stress. Men med rätt timing, bra vatten och en skyddad plats belönar hon dig med krispiga, anissmakande knölar.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[5,6]},days:"65-90",spacing:"25-30 cm",rowSpacing:"40-50 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Fänkålen vill ha full sol för att utveckla fina knölar. I halvskugga blir knölarna mindre och smaken svagare."},temperature:{min:-2,max:28,ideal:"15-22°C",detail:"Trivs bäst i sval-varm temperatur. Tål lätt frost ner till -2°C men ogillar kyla under etableringen - det triggar blomning. Temperaturer över 28°C stressar henne och kan också ge skottbildning."},wind:{level:"Skyddat",detail:"Vill stå skyddat. Kall vind stressar och ökar risken för att hon skjuter i blom. En varm, vindskyddad plats är nyckeln till fina knölar."}},watering:{need:"Medel-Hög",icon:"water",summary:"Fänkålen behöver jämn fukt - torka är hennes största fiende. Ojämn vattning leder rakt till blomning istället för fina knölar.",phases:[{phase:"Etablering (0-3 veckor)",need:"Hög",tip:"Håll jämnt fuktig efter utplantering eller direktsådd. Uttorkad jord under etableringen är den vanligaste orsaken till att hon skjuter i blom."},{phase:"Tillväxt (3-8 veckor)",need:"Medel-Hög",tip:"Vattna regelbundet, minst varannan dag vid torrt väder. Mulcha runt plantorna för att hålla fukten jämn."},{phase:"Knölbildning (8+ veckor)",need:"Hög",tip:"Nu svälljer knölen - håll jämnt fuktig. Kupa jord runt knölen för blekning och skydd."}],mistakes:["Låta jorden torka ut - triggar blomning snabbare än något annat","Ojämn vattning som ger sprickor i knölen","Vattna ovanifrån och blöta ner hjärtat - kan ge röta"],tip:"Mulcha ordentligt runt plantorna med gräsklipp eller halmhack. Det håller fukten jämn och minskar stressen - och det är stress som gör att fänkålen blommar istället för att bilda knöl."},soil:"Djup, mullrik, väldränerad jord. Gärna sandblandad lera som håller fukt utan att bli vattensjuk. Fänkålen vill ha det näringsrikt - till skillnad från moroten gillar hon gödslad jord.",soilTips:["Blanda in rikligt med kompost eller brunnen stallgödsel innan plantering","Jorden ska vara lucker och djup - knölen sitter halvt ovanpå marken men rötterna går djupt","Undvik packad lerjord - den ger dålig dränering och stressar plantorna","Kalka om pH är under 6.0 - fänkålen gillar det neutralt"],timeline:{1:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"seedling"},{phase:"Direktså (alternativ)",months:"Apr-Maj",icon:"seedling"},{phase:"Kupa knölar",months:"Jun-Jul",icon:"scissors"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"seedling"},{phase:"Direktså (alternativ)",months:"Maj-Jun",icon:"seedling"},{phase:"Kupa knölar",months:"Jul-Aug",icon:"scissors"},{phase:"Skörd",months:"Aug-Okt",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut (växthus)",months:"Maj-Jun",icon:"seedling"},{phase:"Kupa knölar",months:"Jul-Aug",icon:"scissors"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:10,K:10,label:"Förodling"},{month:"Maj",N:40,P:20,K:15,label:"Utplantering"},{month:"Jun",N:70,P:30,K:25,label:"Tillväxt"},{month:"Jul",N:80,P:45,K:40,label:"Knölbildning"},{month:"Aug",N:50,P:60,K:60,label:"Knölmognad"},{month:"Sep",N:20,P:40,K:50,label:"Skörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med väl brunnen kompost eller stallgödsel. Fänkålen är mer näringskrävande än moroten - hon vill ha det rejält."},{timing:"Tillväxtfas",tip:"Ge flytande näring (brännässelvatten eller alggödsel) varannan vecka. Kväve driver bladtillväxt som ger energi till knölen."},{timing:"Knölbildning",tip:"Skifta till kaliumrik gödsel (vedaska, stenmjöl) som stöttar knölens utveckling. Minska kvävet gradvis."},{timing:"Kupning",tip:"Kupa jord runt knölen och toppdressera med kompost. Kupningen bleker knölen och gör den mildare och vitare."}],companions:{good:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallaten fungerar som levande marktäckare som håller fukten jämn runt fänkålen"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Trivs i samma varma, fuktiga miljö och stör inte varandra"},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Fixerar kväve i jorden som fänkålen tacksamt tar emot"}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Fänkål utsöndrar ämnen som hämmar tomatens tillväxt - håll dem isär"},{id:"dill",name:"Dill",icon:"herb",why:"Kan enligt traditionell odlingskunskap påverka varandras smak vid samodling. Håll dem isär för säkerhets skull. Delar dessutom morotsfluga-risk."},{id:"morot",name:"Morot",icon:"morot",why:"Samma familj - lockar morotsflugan och delar sjukdomar"}]},rotation:{avoid:[{id:"morot",name:"Morot",category:"grönsaker"},{id:"palsternacka",name:"Palsternacka",category:"grönsaker"},{id:"dill",name:"Dill",category:"kryddor"},{id:"persilja",name:"Persilja",category:"kryddor"},{name:"Selleri",category:"grönsaker"}],avoidWhy:"Alla flockblommiga delar sjukdomar och skadedjur som morotsflugan. Vänta minst 3-4 år innan du odlar fänkål på samma plats igen.",goodBefore:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"bondbona",name:"Bondböna",category:"grönsaker"},{id:"potatis",name:"Potatis",category:"grönsaker"}],goodBeforeWhy:"Baljväxter fixerar kväve som fänkålen älskar. Potatis luckrar jorden fint med sin jordbearbetning.",goodAfter:[{name:"Kål",category:"grönsaker"},{id:"lok",name:"Lök",category:"grönsaker"},{id:"sallat",name:"Sallat",category:"grönsaker"}],goodAfterWhy:"Fänkålens djupa rötter luckrar jorden bra. Kål och lök drar nytta av den fina strukturen och har helt andra skadedjur."},varieties:[{name:"Zefa Fino",zones:[1,2,3,4,5],note:"Pålitlig OP-sort med kompakta knölar. Snabb mognad och bra motståndskraft mot skottbildning. Finns hos Runåbergs."},{name:"Finale",zones:[1,2,3,4],note:"Sen OP-sort som ger stora, tunga knölar. Passar bäst i södra Sverige där säsongen är längre. Finns hos Impecta."},{name:"Romanesco",zones:[1,2,3,4],note:'Italiensk OP-sort med kraftig anissmak. Perfekt för den som vill ha den "riktiga" fänkålssmaken. Internationella fröhus.'},{name:"Perfection",zones:[1,2,3,4,5],note:"Pålitlig OP-sort med jämna, runda knölar. Utvecklad för kallare, nordligare klimat. Finns hos Runåbergs."}],problems:[{name:"Skottbildning (blomning)",symptom:"Plantan skjuter upp en blomstjälk istället för att bilda knöl",fix:"Det viktigaste problemet att förebygga! Orsaker: torka, kyla vid utplantering, för tidigt utsäde, omplanterings-chock. Förodla i stora krukor och störa inte rötterna. Eller direktså. Jämn fukt och värme är nyckeln."},{name:"Bladlöss",symptom:"Kolonier av gröna eller svarta löss på blad och stammar, klibbig honungsdagg",fix:"Spola av med vatten. Locka nyckelpigor och parasitsteklar med blommande växter i närheten. Såpvatten vid kraftig attack."},{name:"Sniglar",symptom:"Oregelbundna hål i blad, slemspår, unga plantor helt avätna",fix:"Snigelstängsel av kopparband runt odlingen. Ölglas. Kontrollera tidiga morgnar och kvällar. Unga plantor är mest utsatta."},{name:"Morotsflugan",symptom:"Rostbruna gångar i roten, vissna blad",fix:"Fiberduk vid sådd/utplantering. Samodla med lök. Undvik att odla nära morot, palsternacka och dill."}],goodToKnow:[{icon:"warning",title:"Skottbildning - fänkålens stora akilleshäl",text:"Fänkålen skjuter i blom vid minsta stress: torka, kyla, vind, rotskada vid omplantning. Förodla i STORA krukor (minst 8 cm) så rötterna inte störs. Eller direktså och gallra. Jämn fukt och värme i 2-3 veckor efter utplantering är helt avgörande.",severity:"warning"},{icon:"warning",title:"Håll isär från dill",text:"Traditionell odlingskunskap säger att fänkål och dill påverkar varandras smak vid samodling. Botaniskt är det osäkert om de verkligen korsar sig (olika släkten), men håll dem isär för säkerhets skull.",severity:"warning"},{icon:"tip",title:"Kupa för fina vita knölar",text:"När knölen börjar svälla, kupa jord runt den som döljer den nedre halvan. Det bleker knölen och ger en mildare, nötaktigare smak. Samma princip som med purjolök.",severity:"tip"},{icon:"tip",title:"Blasten är också ätbar!",text:"Fänkålens fjäderlika blast har en fin, mild anissmak. Klipp och använd som krydda i sallader, soppor och till fisk. Torka blasten som en exklusiv krydda till vintern.",severity:"tip"},{icon:"tip",title:"Rå fänkål - underskattat gott",text:"Hyvla knölen tunt och blanda med citron, olivolja och parmesan. En fräsch sallad som överraskar alla som tror att fänkål bara är lakrits. Smaken är mildare rå än tillagad.",severity:"tip"},{icon:"calendar",title:"Timing är allt",text:"Fänkålen vill ha det varmt och stabilt. Plantera inte ut för tidigt - vänta tills nätterna håller sig över 8-10°C. En kall natt kan vara allt som behövs för att trigga blomning.",severity:"tip"}],sowing:{method:"both",label:"Förodla eller direktså",description:"Fänkålen kan förodlas inomhus eller direktsås. Förodling ger ett försprång, men kräver försiktighet - rötterna ogillar att störas. Direktsådd undviker omplanterings-chocken helt.",steps:["Förodla: Så i stora krukor (minst 8 cm) 4-5 veckor innan utplantering","Förodla: Håll jämn värme (18-22°C) och fukt under groningen","Förodla: Härda av plantorna gradvis under en vecka innan utplantering","Förodla: Plantera ut försiktigt utan att störa rotklumpen - rotskada triggar blomning","Direktså: Så direkt på friland när jorden är minst 12°C","Direktså: Så 2-3 frön per plats med 25-30 cm avstånd","Direktså: Täck med 1-2 cm jord och vattna försiktigt","Gallra till en planta per plats när de har 3-4 riktiga blad"],tips:["Förodla i torvkrukor eller djupa pluggar som planteras ut direkt - undviker rotskada","Direktsådd i juni ger ofta bäst resultat - jorden är varm och dagarna långa","Vänta med utplantering tills nätterna håller sig över 8-10°C","Blötlägg fröna i ljummet vatten 24 timmar innan sådd för snabbare groning"],indoorWeeks:"4-5 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!0,description:"Knölfänkålen är biologiskt tvåårig men kan tvingas blomma första året genom stress. Under nordiska förhållanden behöver du oftast övervintra en planta för frösättning - eller utnyttja en stressblommande planta.",steps:["Välj den bästa plantan - sen blomning och fin knöl är önskvärda egenskaper","Låt plantan stå kvar och blomma (gulvita flockar)","Vänta tills fröna blir bruna och börjar lossna","Klipp av hela flocken och torka inomhus i en papperspåse","Gnugga loss fröna och rensa bort skräp","Förvara svalt och torrt i märkt påse"],isolation:"Korsar med andra fänkålstyper (kryddfänkål, vild fänkål). Isolera med minst 500 m för sortrent frö. Traditionellt hålls fänkål och dill isär, men botaniskt är det osäkert om de verkligen korsar sig.",storageYears:"2-3 år",tip:"Fänkålsfrö håller bättre än palsternacksfrö men inte lika bra som morotsfrö. Använd helst inom 2 år. Fröna kan förresten användas som krydda - fin anissmak i bröd och matlagning!"},storage:{shelfLife:"1-2 veckor (färsk), längre bearbetad",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Bästa sättet för färsk fänkål. Skär bort blasten (spara den som krydda!), linda in knölen i fuktig hushållspapper och lägg i plastpåse. Håller sig krispig i 1-2 veckor.",best:!0},{method:"Frysa (blancherad)",icon:"snowflake",duration:"6-8 månader",description:"Skär knölen i bitar och blanchera 2-3 minuter. Kyl snabbt och frys in. Perfekt för soppor, gratänger och grytor. Texturen blir mjukare men smaken bevaras fint.",best:!1},{method:"Torka (blast som krydda)",icon:"leaf",duration:"12 månader",description:"Blasten torkas och krossas till en aromatisk krydda med anissmak. Fantastisk till fisk, soppor och bröd. Häng blasten i knippen eller torka i ugn på 40°C.",best:!1}],tips:["Skörda hela knölen genom att skära av strax under jordytan","Spara alltid blasten - den är en krydda värd att ta tillvara","Fänkål tappar crunch snabbt efter skörd - ät den så färsk som möjligt","Skär inte knölen förrän du ska använda den - snittytorna oxiderar och blir bruna"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}};export{n as fankal};
